using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.Extensions.Options;
using TestProject.Configuration;
using TestProject.Models;

namespace TestProject.Services;

/// <summary>
/// Path-safe implementation of <see cref="IFileService"/> that confines every
/// operation to a single home directory. The root path is computed at
/// construction time, but the directory itself is created lazily on first use
/// so that disk I/O (and any failure it might raise) is decoupled from DI
/// resolution. Any relative path that normalizes to a location outside the
/// home root causes an <see cref="ArgumentException"/> to be thrown before any
/// disk access.
/// </summary>
public sealed class FileService : IFileService
{
    private const int MaxSearchResults = 500;

    /// <summary>
    /// Maximum recursion depth permitted for <see cref="CopyDirectory"/>. A
    /// copy that recurses this many levels deep is treated as a pathological or
    /// self-referential tree and aborted with <see cref="IOException"/> to
    /// guard against stack overflow.
    /// </summary>
    private const int MaxCopyDepth = 32;

    private readonly Lazy<string> _rootLazy;

    public FileService(IOptions<FileServiceOptions> options, IWebHostEnvironment env)
    {
        // Only compute the resolved path here. Creating the directory (and
        // surfacing any I/O failure) is deferred to first use via the Lazy,
        // which is thread-safe so the directory is materialized exactly once
        // even under concurrent first-access.
        _rootLazy = new Lazy<string>(
            () =>
            {
                var root = Path.GetFullPath(Path.Combine(
                    env.ContentRootPath,
                    options.Value.HomeDirectory ?? "Home"));
                Directory.CreateDirectory(root);
                return root;
            },
            LazyThreadSafetyMode.ExecutionAndPublication);
    }

    /// <summary>
    /// The resolved home root, materializing it on first access.
    /// </summary>
    private string Root => _rootLazy.Value;

    // =====================================================================
    // IFileService
    // =====================================================================

    /// <inheritdoc />
    public BrowseResultDto Browse(string relativePath)
    {
        var full = SafeResolve(relativePath);
        var relative = ToRelative(full);

        // Enumerate files and directories in a single pass, avoiding the
        // double traversal (and double array allocation) of separate
        // GetDirectories/GetFiles calls. Name, FullName, and LastWriteTimeUtc
        // are exposed by the shared FileSystemInfo base; only the file size
        // requires the FileInfo cast.
        var entries = new List<FileEntryDto>();

        foreach (var info in new DirectoryInfo(full).EnumerateFileSystemInfos())
        {
            if (info is DirectoryInfo directoryInfo)
            {
                entries.Add(new FileEntryDto(
                    Name: directoryInfo.Name,
                    Path: ToRelative(directoryInfo.FullName),
                    IsDirectory: true,
                    Size: 0,
                    LastModified: directoryInfo.LastWriteTimeUtc));
            }
            else
            {
                var fileInfo = (FileInfo)info;
                entries.Add(new FileEntryDto(
                    Name: fileInfo.Name,
                    Path: ToRelative(fileInfo.FullName),
                    IsDirectory: false,
                    Size: fileInfo.Length,
                    LastModified: fileInfo.LastWriteTimeUtc));
            }
        }

        // Directories first, then files, each group sorted by name (OrdinalIgnoreCase).
        entries.Sort(CompareEntries);

        var folderCount = 0;
        var fileCount = 0;
        var totalSize = 0L;
        foreach (var entry in entries)
        {
            if (entry.IsDirectory)
            {
                folderCount++;
            }
            else
            {
                fileCount++;
                totalSize += entry.Size;
            }
        }

        var parent = ComputeParent(relative);

        return new BrowseResultDto(relative, parent, entries, folderCount, fileCount, totalSize);
    }

    /// <inheritdoc />
    public SearchResultDto Search(string query, string relativePath)
    {
        var full = SafeResolve(relativePath);
        var relative = ToRelative(full);

        var results = new List<FileEntryDto>(MaxSearchResults);

        var stack = new Stack<string>();
        stack.Push(full);

        while (stack.Count > 0 && results.Count < MaxSearchResults)
        {
            var current = stack.Pop();

            string[] subdirectories;
            string[] files;
            try
            {
                subdirectories = Directory.GetDirectories(current);
                files = Directory.GetFiles(current);
            }
            catch (UnauthorizedAccessException)
            {
                continue;
            }
            catch (DirectoryNotFoundException)
            {
                continue;
            }

            foreach (var dir in subdirectories)
            {
                if (results.Count >= MaxSearchResults)
                {
                    break;
                }

                var info = new DirectoryInfo(dir);
                if (info.Name.Contains(query, StringComparison.OrdinalIgnoreCase))
                {
                    results.Add(new FileEntryDto(
                        Name: info.Name,
                        Path: ToRelative(dir),
                        IsDirectory: true,
                        Size: 0,
                        LastModified: info.LastWriteTimeUtc));
                }

                stack.Push(dir);
            }

            foreach (var file in files)
            {
                if (results.Count >= MaxSearchResults)
                {
                    break;
                }

                var info = new FileInfo(file);
                if (info.Name.Contains(query, StringComparison.OrdinalIgnoreCase))
                {
                    results.Add(new FileEntryDto(
                        Name: info.Name,
                        Path: ToRelative(file),
                        IsDirectory: false,
                        Size: info.Length,
                        LastModified: info.LastWriteTimeUtc));
                }
            }
        }

        return new SearchResultDto(query, relative, results);
    }

    /// <inheritdoc />
    public string ResolveFullPath(string relativePath) => SafeResolve(relativePath);

    /// <inheritdoc />
    public async Task UploadAsync(string relativeDirPath, IFormFile file)
    {
        var dir = SafeResolve(relativeDirPath);
        Directory.CreateDirectory(dir);

        var path = Path.Combine(dir, file.FileName);
        await using var fs = File.Create(path);
        await file.CopyToAsync(fs);
    }

    /// <summary>
    /// Deletes the file or directory (recursively) at <paramref name="relativePath"/>.
    /// Deleting a non-existent path succeeds silently — the post-condition
    /// (entry gone) is already met. This is achieved without an up-front
    /// <c>Exists</c> check, eliminating the check-then-act (TOCTOU) window in
    /// which a concurrent delete could cause a spurious
    /// <see cref="DirectoryNotFoundException"/>: the delete is attempted, and
    /// a missing-path outcome is treated as success rather than a failure.
    /// </summary>
    public void Delete(string relativePath)
    {
        var path = SafeResolve(relativePath);

        try
        {
            try
            {
                // Attempt the directory delete first. On a real file (or a
                // missing path) this throws DirectoryNotFoundException, which
                // is the signal to fall through to the file form.
                Directory.Delete(path, recursive: true);
            }
            catch (DirectoryNotFoundException)
            {
                // Not a directory (or already gone). File.Delete is itself a
                // no-op when the target file is absent.
                File.Delete(path);
            }
        }
        catch (DirectoryNotFoundException)
        {
            // Both the directory and file forms reported the path (or an
            // ancestor) as absent. The post-condition — the entry no longer
            // exists — is satisfied, so treat this as success.
        }
    }

    /// <inheritdoc />
    public void Move(MoveRequest request)
    {
        var source = SafeResolve(request.SourcePath);
        var destination = SafeResolve(request.DestinationPath);

        // Path.GetDirectoryName returns null when the destination is a
        // filesystem root (e.g. the home root itself). Moving an entry onto a
        // filesystem root is nonsensical within the home-directory sandbox, so
        // surface a clear error rather than letting
        // Directory.CreateDirectory(null) crash with an opaque
        // ArgumentNullException.
        var parent = Path.GetDirectoryName(destination);
        if (string.IsNullOrEmpty(parent))
        {
            throw new ArgumentException("Invalid destination path", nameof(request));
        }

        Directory.CreateDirectory(parent);

        if (Directory.Exists(source))
        {
            Directory.Move(source, destination);
        }
        else
        {
            File.Move(source, destination);
        }
    }

    /// <inheritdoc />
    public void Copy(CopyRequest request)
    {
        var source = SafeResolve(request.SourcePath);
        var destination = SafeResolve(request.DestinationPath);

        if (Directory.Exists(source))
        {
            CopyDirectory(source, destination, depth: 0);
        }
        else
        {
            File.Copy(source, destination, overwrite: false);
        }
    }

    // =====================================================================
    // Helpers
    // =====================================================================

    /// <summary>
    /// Combines the home root with <paramref name="relativePath"/>, normalizes
    /// the result, and verifies it stays within the root. A null, empty, or
    /// whitespace path resolves to the root itself. Anything that escapes the
    /// root throws <see cref="ArgumentException"/>.
    /// </summary>
    private string SafeResolve(string relativePath)
    {
        var root = Root;

        if (string.IsNullOrWhiteSpace(relativePath))
        {
            return root;
        }

        var full = Path.GetFullPath(Path.Combine(root, relativePath));

        var isRoot = string.Equals(full, root, StringComparison.Ordinal);
        var isInsideRoot = full.StartsWith(root + Path.DirectorySeparatorChar, StringComparison.Ordinal);

        if (!isRoot && !isInsideRoot)
        {
            throw new ArgumentException("Invalid path");
        }

        return full;
    }

    /// <summary>
    /// Converts an absolute path inside the root to a forward-slash relative
    /// path. The root itself becomes the empty string.
    /// </summary>
    private string ToRelative(string full)
    {
        var root = Root;
        return full
            .Substring(root.Length)
            .TrimStart(Path.DirectorySeparatorChar, Path.AltDirectorySeparatorChar)
            .Replace('\\', '/');
    }

    /// <summary>
    /// Computes the normalized (forward-slash) parent of a relative path.
    /// Returns <c>null</c> when <paramref name="relative"/> is the root (empty),
    /// or the empty string when the path is a direct child of the root.
    /// </summary>
    private static string? ComputeParent(string relative)
    {
        if (string.IsNullOrEmpty(relative))
        {
            return null;
        }

        return Path.GetDirectoryName(relative)?.Replace('\\', '/') ?? string.Empty;
    }

    /// <summary>
    /// Sorts directories before files, ordering each group by name using
    /// <see cref="StringComparison.OrdinalIgnoreCase"/>.
    /// </summary>
    private static int CompareEntries(FileEntryDto a, FileEntryDto b)
    {
        if (a.IsDirectory != b.IsDirectory)
        {
            return a.IsDirectory ? -1 : 1;
        }

        return string.Compare(a.Name, b.Name, StringComparison.OrdinalIgnoreCase);
    }

    /// <summary>
    /// Recursively copies a directory tree, preserving structure. Existing
    /// files are not overwritten, matching the no-overwrite contract of
    /// <see cref="File.Copy(string, string, bool)"/>. The recursion is bounded
    /// by <see cref="MaxCopyDepth"/>: each nested directory increments
    /// <paramref name="depth"/> by one, and once it reaches the limit the copy
    /// is aborted with <see cref="IOException"/> to prevent stack overflow on
    /// pathological or self-referential trees.
    /// </summary>
    /// <param name="source">Absolute path to the directory to copy from.</param>
    /// <param name="destination">Absolute path to the directory to copy into.</param>
    /// <param name="depth">Current recursion depth, seeded at zero by
    /// <see cref="Copy"/>.</param>
    private static void CopyDirectory(string source, string destination, int depth)
    {
        if (depth >= MaxCopyDepth)
        {
            throw new IOException("Directory copy depth limit exceeded (possible cycle)");
        }

        Directory.CreateDirectory(destination);

        foreach (var file in Directory.GetFiles(source))
        {
            File.Copy(file, Path.Combine(destination, Path.GetFileName(file)), overwrite: false);
        }

        foreach (var directory in Directory.GetDirectories(source))
        {
            CopyDirectory(directory, Path.Combine(destination, Path.GetFileName(directory)), depth + 1);
        }
    }
}

using System;
using System.IO;
using System.Text.RegularExpressions;
using Xunit;

namespace TestProject.Tests;

/// <summary>
/// Tests for the dependency-injection wiring and HTTP request-pipeline
/// ordering in <c>Program.cs</c>.
///
/// The application bootstrap is expected to:
/// <list type="bullet">
/// <item>Bind <see cref="TestProject.FileServiceOptions"/> from the
/// "FileService" configuration section via
/// <c>builder.Services.Configure&lt;FileServiceOptions&gt;(
/// builder.Configuration.GetSection("FileService"))</c>.</item>
/// <item>Register <see cref="TestProject.Services.IFileService"/> backed by
/// <see cref="TestProject.Services.FileService"/> as a singleton.</item>
/// <item>Configure the middleware pipeline in the exact order
/// <c>UseHttpsRedirection</c> -&gt; <c>UseDefaultFiles</c> -&gt;
/// <c>UseStaticFiles</c> -&gt; <c>MapControllers</c> -&gt;
/// <c>MapFallbackToFile("index.html")</c> -&gt; <c>Run</c>.</item>
/// </list>
///
/// These assertions parse the source of <c>Program.cs</c> directly so the
/// contract is locked in regardless of formatting choices (fully-qualified
/// names or added <c>using</c> directives). The file is located by walking up
/// from the test output directory to the folder that contains
/// <c>TestProject.csproj</c>.
/// </summary>
public class ProgramWiringTests
{
    private static readonly string ProgramSource = LoadProgramSource();

    private const string OptionsConfigurePattern =
        @"Services\s*\.\s*Configure\s*<[^>]*FileServiceOptions[^>]*>";

    private const string FileServiceSectionPattern =
        @"GetSection\s*\(\s*""FileService""\s*\)";

    private const string SingletonPattern =
        @"Services\s*\.\s*AddSingleton\s*<[^>]*IFileService[^>]*,\s*[^>]*FileService\s*>";

    private const string FallbackIndexHtmlPattern =
        @"MapFallbackToFile\s*\(\s*""index\.html""\s*\)";

    private const string RunPattern = @"\.\s*Run\s*\(\s*\)";

    /// <summary>
    /// Walks up from the test assembly output directory until it finds a
    /// folder containing both <c>TestProject.csproj</c> and <c>Program.cs</c>,
    /// then returns the Program.cs source text.
    /// </summary>
    private static string LoadProgramSource()
    {
        var dir = new DirectoryInfo(AppContext.BaseDirectory);
        while (dir is not null)
        {
            var csprojPath = Path.Combine(dir.FullName, "TestProject.csproj");
            if (File.Exists(csprojPath))
            {
                var programPath = Path.Combine(dir.FullName, "Program.cs");
                if (File.Exists(programPath))
                {
                    return File.ReadAllText(programPath);
                }
            }

            dir = dir.Parent;
        }

        throw new FileNotFoundException(
            "Could not locate Program.cs next to TestProject.csproj by walking up " +
            "from the test output directory (" + AppContext.BaseDirectory + ").");
    }

    /// <summary>Returns the index of the first match of <paramref name="pattern"/>,
    /// or -1 when it is absent.</summary>
    private static int IndexOf(string pattern)
    {
        var match = Regex.Match(ProgramSource, pattern);
        return match.Success ? match.Index : -1;
    }

    /// <summary>Returns the index of the first occurrence of a simple method
    /// call like <c>UseDefaultFiles(</c>, or -1 when absent.</summary>
    private static int CallIndex(string methodName) =>
        IndexOf(Regex.Escape(methodName) + @"\s*\(");

    /// <summary>Counts how many times <paramref name="pattern"/> matches.</summary>
    private static int Count(string pattern) =>
        Regex.Matches(ProgramSource, pattern).Count;

    private static void AssertPresent(string pattern, string description)
    {
        Assert.True(IndexOf(pattern) >= 0,
            $"Expected {description} to be present in Program.cs.");
    }

    private static void AssertCallOrder(string earlier, string later)
    {
        var earlierIdx = CallIndex(earlier);
        var laterIdx = CallIndex(later);

        Assert.True(earlierIdx >= 0, $"Expected '{earlier}(' in Program.cs.");
        Assert.True(laterIdx >= 0, $"Expected '{later}(' in Program.cs.");
        Assert.True(earlierIdx < laterIdx,
            $"'{earlier}' must appear before '{later}' in the Program.cs pipeline.");
    }

    // =====================================================================
    // Service registration: FileServiceOptions
    // =====================================================================

    [Fact]
    public void Program_Registers_FileServiceOptions_OnServicesCollection()
    {
        AssertPresent(OptionsConfigurePattern,
            "builder.Services.Configure<...FileServiceOptions>");
    }

    [Fact]
    public void Program_Registers_FileServiceOptions_FromFileServiceSection()
    {
        var configureIdx = IndexOf(OptionsConfigurePattern);
        var sectionIdx = IndexOf(FileServiceSectionPattern);

        Assert.True(sectionIdx >= 0,
            "Expected builder.Configuration.GetSection(\"FileService\") in Program.cs.");

        // The section should be supplied to the Configure call (i.e. it appears
        // right after the Configure<FileServiceOptions> token).
        Assert.True(configureIdx >= 0 && sectionIdx > configureIdx,
            "GetSection(\"FileService\") should be the argument passed to " +
            "Configure<FileServiceOptions>.");
        Assert.True(sectionIdx - configureIdx < 250,
            "GetSection(\"FileService\") should be supplied directly to the " +
            "Configure<FileServiceOptions>(...) call.");
    }

    [Fact]
    public void Program_Registers_FileServiceOptions_AfterAddControllers_AndBeforeBuild()
    {
        var addControllers = CallIndex("AddControllers");
        var configure = IndexOf(OptionsConfigurePattern);
        var build = IndexOf(@"\.\s*Build\s*\(\s*\)");

        Assert.True(addControllers >= 0 && configure > addControllers,
            "Configure<FileServiceOptions> must be added after AddControllers().");
        Assert.True(build < 0 || configure < build,
            "Configure<FileServiceOptions> must be added before builder.Build().");
    }

    // =====================================================================
    // Service registration: IFileService -> FileService singleton
    // =====================================================================

    [Fact]
    public void Program_Registers_IFileService_AsSingleton_FileService()
    {
        AssertPresent(SingletonPattern,
            "builder.Services.AddSingleton<...IFileService..., ...FileService>()");
    }

    [Fact]
    public void Program_Registers_IFileService_AsSingleton_ExactlyOnce()
    {
        Assert.Equal(1, Count(SingletonPattern));
    }

    [Fact]
    public void Program_Registers_IFileService_AfterAddControllers_AndBeforeBuild()
    {
        var addControllers = CallIndex("AddControllers");
        var singleton = IndexOf(SingletonPattern);
        var build = IndexOf(@"\.\s*Build\s*\(\s*\)");

        Assert.True(addControllers >= 0 && singleton > addControllers,
            "AddSingleton<IFileService, FileService> must be added after AddControllers().");
        Assert.True(build < 0 || singleton < build,
            "AddSingleton<IFileService, FileService> must be added before builder.Build().");
    }

    [Fact]
    public void Program_Registers_Options_BeforeIFileService()
    {
        var configure = IndexOf(OptionsConfigurePattern);
        var singleton = IndexOf(SingletonPattern);

        Assert.True(configure >= 0 && singleton >= 0 && configure < singleton,
            "FileServiceOptions should be configured before the FileService singleton " +
            "that depends on them is registered.");
    }

    // =====================================================================
    // Pipeline statements are present exactly once
    // =====================================================================

    [Fact]
    public void Program_Pipeline_UsesHttpsRedirection_ExactlyOnce()
    {
        Assert.Equal(1, Count(@"UseHttpsRedirection\s*\("));
    }

    [Fact]
    public void Program_Pipeline_UsesDefaultFiles_ExactlyOnce()
    {
        Assert.Equal(1, Count(@"UseDefaultFiles\s*\("));
    }

    [Fact]
    public void Program_Pipeline_UsesStaticFiles_ExactlyOnce()
    {
        Assert.Equal(1, Count(@"UseStaticFiles\s*\("));
    }

    [Fact]
    public void Program_Pipeline_MapsControllers_ExactlyOnce()
    {
        Assert.Equal(1, Count(@"MapControllers\s*\("));
    }

    [Fact]
    public void Program_Pipeline_MapsFallbackToIndexHtml_ExactlyOnce()
    {
        Assert.Equal(1, Count(FallbackIndexHtmlPattern));
    }

    // =====================================================================
    // Pipeline ordering
    // =====================================================================

    [Fact]
    public void Program_Pipeline_HttpsRedirection_ComesBeforeDefaultFiles()
    {
        AssertCallOrder("UseHttpsRedirection", "UseDefaultFiles");
    }

    [Fact]
    public void Program_Pipeline_DefaultFiles_ComesBeforeStaticFiles()
    {
        // DefaultFiles MUST run before StaticFiles so that requests for "/"
        // are rewritten to index.html before the static file middleware looks
        // for them.
        AssertCallOrder("UseDefaultFiles", "UseStaticFiles");
    }

    [Fact]
    public void Program_Pipeline_StaticFiles_ComesBeforeMapControllers()
    {
        AssertCallOrder("UseStaticFiles", "MapControllers");
    }

    [Fact]
    public void Program_Pipeline_MapControllers_ComesBeforeFallback()
    {
        var controllers = CallIndex("MapControllers");
        var fallback = IndexOf(FallbackIndexHtmlPattern);

        Assert.True(controllers >= 0, "Expected 'MapControllers(' in Program.cs.");
        Assert.True(fallback >= 0, "Expected MapFallbackToFile(\"index.html\") in Program.cs.");
        Assert.True(controllers < fallback,
            "MapControllers must come before MapFallbackToFile so that API routes " +
            "take precedence over the SPA fallback.");
    }

    [Fact]
    public void Program_Pipeline_Fallback_ComesBeforeRun()
    {
        var fallback = IndexOf(FallbackIndexHtmlPattern);
        var run = IndexOf(RunPattern);

        Assert.True(fallback >= 0, "Expected MapFallbackToFile(\"index.html\") in Program.cs.");
        Assert.True(run >= 0, "Expected app.Run() in Program.cs.");
        Assert.True(fallback < run,
            "MapFallbackToFile must be registered before app.Run().");
    }

    [Fact]
    public void Program_Pipeline_Build_ComesBeforeAnyMiddleware()
    {
        var build = IndexOf(@"\.\s*Build\s*\(\s*\)");
        var https = CallIndex("UseHttpsRedirection");

        Assert.True(build >= 0, "Expected builder.Build() in Program.cs.");
        Assert.True(https >= 0, "Expected UseHttpsRedirection() in Program.cs.");
        Assert.True(build < https,
            "builder.Build() must occur before the request pipeline is configured.");
    }

    [Fact]
    public void Program_Pipeline_FullOrder_IsHttpsRedirection_DefaultFiles_StaticFiles_MapControllers_Fallback_Run()
    {
        var https = CallIndex("UseHttpsRedirection");
        var defaults = CallIndex("UseDefaultFiles");
        var stat = CallIndex("UseStaticFiles");
        var controllers = CallIndex("MapControllers");
        var fallback = IndexOf(FallbackIndexHtmlPattern);
        var run = IndexOf(RunPattern);

        Assert.True(https >= 0 && defaults >= 0 && stat >= 0 &&
                    controllers >= 0 && fallback >= 0 && run >= 0,
            "All six expected pipeline statements must be present in Program.cs.");

        Assert.True(https < defaults,
            "Order: UseHttpsRedirection must precede UseDefaultFiles.");
        Assert.True(defaults < stat,
            "Order: UseDefaultFiles must precede UseStaticFiles.");
        Assert.True(stat < controllers,
            "Order: UseStaticFiles must precede MapControllers.");
        Assert.True(controllers < fallback,
            "Order: MapControllers must precede MapFallbackToFile.");
        Assert.True(fallback < run,
            "Order: MapFallbackToFile must precede Run.");
    }

    // =====================================================================
    // End-to-end ordering of service registration vs. pipeline
    // =====================================================================

    [Fact]
    public void Program_AllServiceRegistrations_HappenBeforeAnyMiddleware()
    {
        var lastRegistration = Math.Max(
            IndexOf(OptionsConfigurePattern),
            IndexOf(SingletonPattern));
        var firstMiddleware = CallIndex("UseHttpsRedirection");

        Assert.True(lastRegistration >= 0 && firstMiddleware >= 0,
            "Expected both service registrations and pipeline middleware in Program.cs.");
        Assert.True(lastRegistration < firstMiddleware,
            "All DI registrations must occur before the HTTP pipeline is configured.");
    }
}

using System.Collections.Concurrent;
using System.Text;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.Extensions.FileProviders;
using Microsoft.Extensions.Options;
using TestProject.Configuration;
using TestProject.Models;
using TestProject.Services;
using TestProject.Tests.TestHelpers;
using Xunit;

namespace TestProject.Tests.Services;

/// <summary>
/// Functional tests for <see cref="FileService"/>. Each test runs against a
/// unique temporary content root so that tests are fully independent and
/// never touch the real file system outside a scratch directory.
///
/// The service computes its home root once, at construction time, as
/// <c>Path.GetFullPath(Path.Combine(env.ContentRootPath, options.HomeDirectory))</c>.
/// Directory creation is deferred (lazy) until first use, so these tests
/// trigger an operation before asserting the directory exists on disk. Every
/// operation must funnel inputs through a path-safety check so that paths
/// escaping the home root throw <see cref="ArgumentException"/>.
/// </summary>
public class FileServiceTests : IDisposable
{
    private readonly string _contentRoot;

    public FileServiceTests()
    {
        _contentRoot = Directory.CreateTempSubdirectory("fs_test_").FullName;
    }

    public void Dispose()
    {
        try
        {
            Directory.Delete(_contentRoot, recursive: true);
        }
        catch
        {
            // Best effort cleanup; temp dirs may already be gone.
        }
    }

    // Builds a fresh service whose home directory lives under the per-test
    // content root. Returns the absolute, normalized root the service should
    // be treating as its sandbox.
    private (FileService service, string root) CreateService(string homeDirectory = "Home")
    {
        var env = new FakeWebHostEnvironment
        {
            ContentRootPath = _contentRoot
        };
        var options = Options.Create(new FileServiceOptions
        {
            HomeDirectory = homeDirectory
        });

        var service = new FileService(options, env);
        var root = Path.GetFullPath(Path.Combine(_contentRoot, homeDirectory));
        return (service, root);
    }

    // Builds the directory chain {baseDir}/d1/d2/.../d{levels}, creating every
    // intermediate directory along the way, and returns the deepest directory
    // path. `levels` is the number of nested directories beneath baseDir, so a
    // copy of baseDir recurses to depth == levels.
    private static string CreateNestedChain(string baseDir, int levels)
    {
        var current = baseDir;
        for (var i = 1; i <= levels; i++)
        {
            current = Path.Combine(current, $"d{i}");
        }
        Directory.CreateDirectory(current);
        return current;
    }

    // =====================================================================
    // Constructor / root computation
    // =====================================================================

    [Fact]
    public void Constructor_CreatesRootDirectory_WhenItDoesNotExist()
    {
        var home = "BrandNewHome";
        var expectedRoot = Path.GetFullPath(Path.Combine(_contentRoot, home));

